import{c as h,S as a,j as n,m as l}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Đại lý","description":"","frontmatter":{},"headers":[],"relativePath":"admin/dai-ly.md","filePath":"admin/dai-ly.md","lastUpdated":0}'),t={name:"admin/dai-ly.md"};function o(e,i,c,r,u,g){return a(),n("div",null,[...i[0]||(i[0]=[l('<h1 id="đai-ly" tabindex="-1">Đại lý <a class="header-anchor" href="#đai-ly" aria-label="Permalink to “Đại lý”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/business/dealerTeacher</code></p><p>Quản lý hệ thống <strong>đại lý / cộng tác viên bán hàng</strong> ngoài hệ thống nhân viên cơ hữu.</p><h2 id="khai-niem" tabindex="-1">Khái niệm <a class="header-anchor" href="#khai-niem" aria-label="Permalink to “Khái niệm”">​</a></h2><p>Đại lý là <strong>đối tác bên thứ ba</strong> giúp giới thiệu khóa học và nhận chiết khấu. Khác với giáo viên:</p><ul><li>Đại lý không soạn nội dung.</li><li>Đại lý không truy cập khu vực <code>https://lamsonedutech.vn/teacher/...</code>.</li><li>Đại lý có <strong>link giới thiệu riêng</strong> (referral) để track doanh số.</li></ul><h2 id="danh-sach-đai-ly" tabindex="-1">Danh sách đại lý <a class="header-anchor" href="#danh-sach-đai-ly" aria-label="Permalink to “Danh sách đại lý”">​</a></h2><p>Cột chính:</p><ul><li>Tên đại lý / cá nhân</li><li>Số điện thoại, Email</li><li>Mã đại lý (referral code)</li><li>Loại: Cá nhân / Tổ chức</li><li>Cấu hình chiết khấu liên kết</li><li>Doanh số luỹ kế</li><li>Trạng thái</li></ul><h2 id="tao-đai-ly" tabindex="-1">Tạo đại lý <a class="header-anchor" href="#tao-đai-ly" aria-label="Permalink to “Tạo đại lý”">​</a></h2><ol><li>Bấm <strong>Thêm đại lý</strong>.</li><li>Điền: <ul><li><strong>Tên</strong>, <strong>Số điện thoại</strong>, <strong>Email</strong></li><li><strong>Loại</strong> (Cá nhân / Tổ chức)</li><li><strong>Mã đại lý</strong> (referral code) - mặc định tự sinh, có thể đổi</li><li><strong>Địa chỉ</strong>, thông tin ngân hàng (để chi trả chiết khấu)</li></ul></li><li>Lưu.</li></ol><h2 id="ma-gioi-thieu-referral" tabindex="-1">Mã giới thiệu (Referral) <a class="header-anchor" href="#ma-gioi-thieu-referral" aria-label="Permalink to “Mã giới thiệu (Referral)”">​</a></h2><p>Khi đại lý chia sẻ link có chứa mã giới thiệu của họ (vd <code>?ref=NAM2026</code>):</p><ul><li>Học viên click vào link → hệ thống ghi nhận &quot;đại lý giới thiệu&quot;.</li><li>Sau khi học viên mua khóa, hệ thống tự tính chiết khấu cho đại lý.</li></ul><blockquote><p>Link mẫu: <code>https://hsaplus.edu.vn/luyen-tap/gioi-thieu-khoa-hoc/123?ref=NAM2026</code></p></blockquote><h2 id="cau-hinh-chiet-khau-cho-đai-ly" tabindex="-1">Cấu hình chiết khấu cho đại lý <a class="header-anchor" href="#cau-hinh-chiet-khau-cho-đai-ly" aria-label="Permalink to “Cấu hình chiết khấu cho đại lý”">​</a></h2><p>→ Sang <a href="./chiet-khau">Chiết khấu</a> → chọn người nhận là đại lý vừa tạo → đặt tỷ lệ.</p><h2 id="xem-hieu-qua-cua-đai-ly" tabindex="-1">Xem hiệu quả của đại lý <a class="header-anchor" href="#xem-hieu-qua-cua-đai-ly" aria-label="Permalink to “Xem hiệu quả của đại lý”">​</a></h2><ul><li>Bấm vào dòng đại lý để mở chi tiết.</li><li>Tab <strong>Doanh số</strong>: liệt kê hóa đơn được giới thiệu.</li><li>Tab <strong>Chiết khấu</strong>: tiền chiết khấu đã/chưa thanh toán.</li></ul><h2 id="thanh-toan-cho-đai-ly" tabindex="-1">Thanh toán cho đại lý <a class="header-anchor" href="#thanh-toan-cho-đai-ly" aria-label="Permalink to “Thanh toán cho đại lý”">​</a></h2><ol><li>Cuối kỳ, xuất báo cáo chiết khấu của đại lý.</li><li>Đối soát.</li><li>Chuyển khoản theo thông tin ngân hàng đã lưu.</li><li>Đánh dấu <strong>Đã thanh toán</strong> trên hệ thống để khép sổ.</li></ol><h2 id="tam-dung-xoa-đai-ly" tabindex="-1">Tạm dừng / Xóa đại lý <a class="header-anchor" href="#tam-dung-xoa-đai-ly" aria-label="Permalink to “Tạm dừng / Xóa đại lý”">​</a></h2><ul><li><strong>Tạm dừng</strong>: link giới thiệu vẫn còn nhưng giao dịch sau không tính chiết khấu.</li><li><strong>Xóa</strong>: chỉ xóa được khi chưa có giao dịch.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Đại lý báo &quot;doanh số không khớp với báo cáo họ tự kê khai&quot;.</strong> → Có thể do học viên đã xóa cookie / vào link không đúng. Đối chiếu mã referral trong hóa đơn để xác minh.</p><p><strong>Có thể vừa là giáo viên vừa là đại lý không?</strong> → Có. Tạo 2 cấu hình chiết khấu khác nhau cho cùng người. Khi học viên mua khóa của giáo viên đó qua link giới thiệu của chính họ, có thể nhận cả 2 mức chiết khấu (tùy quy định).</p>',26)])])}const k=h(t,[["render",o]]);export{d as __pageData,k as default};
